export const getAdminCalendarUrl = (params: AdminCalendarParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/calendar?${stringifiedParams}`
    : `/api/admin/calendar`;
};

export const adminCalendar = async (
  params: AdminCalendarParams,
  options?: RequestInit,
): Promise<AdminCalendar200Item[]> => {
  return customFetch<AdminCalendar200Item[]>(getAdminCalendarUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getAdminCalendarQueryKey = (params?: AdminCalendarParams) => {
  return [`/api/admin/calendar`, ...(params ? [params] : [])] as const;
};

